#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_LEN 500005

typedef struct {char ch; int freq;} Pair;

int cmp(const void *a, const void *b) {
    const Pair *x = (const Pair *)a;
    const Pair *y = (const Pair *)b;
    if (x->freq != y->freq) return y->freq - x->freq; // descending frequency
    return (int)x->ch - (int)y->ch; // ascending ASCII
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buffer[MAX_LEN];
    getchar(); // consume newline after T
    while (T--) {
        if (!fgets(buffer, MAX_LEN, stdin)) break;
        buffer[strcspn(buffer, "\n")] = '\0';
        int freq[256] = {0};
        for (char *p = buffer; *p; ++p) freq[(unsigned char)*p]++;
        Pair arr[256];
        int cnt = 0;
        for (int i = 0; i < 256; ++i) if (freq[i]) {
            arr[cnt].ch = (char)i;
            arr[cnt].freq = freq[i];
            cnt++;
        }
        qsort(arr, cnt, sizeof(Pair), cmp);
        for (int i = 0; i < cnt; ++i) {
            for (int j = 0; j < arr[i].freq; ++j) putchar(arr[i].ch);
        }
        putchar('\n');
    }
    return 0;
}

