        getline(cin, s);
        vector<int> freq(256, 0);
        for (unsigned char c : s) freq[c]++;
        vector<pair<char,int>> vec;
        for (int i = 0; i < 256; ++i) if (freq[i])
            vec.emplace_back((char)i, freq[i]);
        sort(vec.begin(), vec.end(), [](const auto &a, const auto &b){
            if (a.second != b.second) return a.second > b.second; // higher freq first
            return a.first < b.first; // lower ASCII first
        });
        for (auto &p : vec) cout << string(p.second, p.first);
        cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static class Pair {
        char ch;
        int freq;
        Pair(char ch, int freq) { this.ch = ch; this.freq = freq; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            String s = br.readLine();
            int[] freq = new int[256];
            for (int i = 0; i < s.length(); i++) freq[s.charAt(i)]++;
            List<Pair> list = new ArrayList<>();
            for (int i = 0; i < 256; i++) if (freq[i] > 0) list.add(new Pair((char)i, freq[i]));
            list.sort((a, b) -> {
                if (a.freq != b.freq) return b.freq - a.freq; // descending freq
                return a.ch - b.ch; // ascending ASCII
            });
            for (Pair p : list) {
                for (int i = 0; i < p.freq; i++) out.append(p.ch);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

