const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let output = [];
for (let t = 0; t < T; t++) {
  const s = lines[idx++] || '';
  const freq = {};
  for (const ch of s) {
    freq[ch] = (freq[ch] || 0) + 1;
  }
  const chars = Object.keys(freq).sort((a, b) => {
    if (freq[b] !== freq[a]) return freq[b] - freq[a];
    return a < b ? -1 : a > b ? 1 : 0; // ASCII order
  });
  let res = '';
  for (const ch of chars) {
    res += ch.repeat(freq[ch]);
  }
  output.push(res);
}
console.log(output.join('\n'));
